@SpringBootApplication
public class ProductSearchApplication {
    public static void main(String[] args) {
        SpringApplication.run(ProductSearchApplication.class, args);
    }

    @Bean
    public ElasticsearchRestTemplate elasticsearchTemplate() {
        return new ElasticsearchRestTemplate(RestClients.create("http://localhost:9200").build().rest());
    }
}

@Entity
public class Product {
    @Id
    private String id;
    private String name;
    private String description;
    private double price;
    
    // Getters and Setters
}

public interface ProductRepository extends ElasticsearchRepository<Product, String> {
}

@Service
public class ProductService {
    private final ProductRepository productRepository;
    private final ElasticsearchRestTemplate elasticsearchTemplate;

    public ProductService(ProductRepository productRepository, ElasticsearchRestTemplate elasticsearchTemplate) {
        this.productRepository = productRepository;
        this.elasticsearchTemplate = elasticsearchTemplate;
    }

    public void indexProduct(Product product) {
        productRepository.save(product);
    }

    public Page<Product> searchProducts(String query, int page, int size) {
        NativeSearchQuery searchQuery = new NativeSearchQueryBuilder()
                .withQuery(QueryBuilders.multiMatchQuery(query, "name", "description"))
                .withPageable(PageRequest.of(page, size))
                .build();
        return elasticsearchTemplate.queryForPage(searchQuery, Product.class);
    }
}

@RestController
@RequestMapping("/products")
public class ProductController {
    private final ProductService productService;

    public ProductController(ProductService productService) {
        this.productService = productService;
    }

    @PostMapping
    public void addProduct(@RequestBody Product product) {
        productService.indexProduct(product);
    }

    @GetMapping("/search")
    public Page<Product> search(@RequestParam String query, 
                                 @RequestParam(defaultValue = "0") int page, 
                                 @RequestParam(defaultValue = "10") int size) {
        return productService.searchProducts(query, page, size);
    }
}